14	static int get_longest_segment_length(const std::vector<t_segment_inf>& segment_inf) {
15	    int length = 0;
16	
17	    for (const t_segment_inf& seg_info : segment_inf) {
18	        if (seg_info.length > length) {
19	            length = seg_info.length;
20	        }
21	    }
22	
23	    return length;
24	}
25	
26	std::unique_ptr<PlaceDelayModel>
27	PlacementDelayModelCreator::create_delay_model(const t_placer_opts& placer_opts,
28	                                               const t_router_opts& router_opts,
29	                                               const t_crr_opts& crr_opts,
30	                                               const Netlist<>& net_list,
31	                                               t_det_routing_arch& det_routing_arch,
32	                                               const std::vector<t_segment_inf>& segment_inf,
33	                                               const t_chan_width_dist& chan_width_dist,
34	                                               const std::vector<t_direct_inf>& directs,
35	                                               bool is_flat) {
36	    vtr::ScopedStartFinishTimer timer("Computing placement delta delay look-up");
37	
38	    t_chan_width chan_width = setup_chan_width(router_opts, chan_width_dist);
39	
40	    alloc_routing_structs(chan_width,
41	                          router_opts,
42	                          crr_opts,
43	                          det_routing_arch,
44	                          segment_inf,
45	                          directs,
46	                          is_flat);
47	
48	    const RouterLookahead* router_lookahead = get_cached_router_lookahead(det_routing_arch,
49	                                                                          router_opts.lookahead_type,
50	                                                                          router_opts.write_router_lookahead,
51	                                                                          router_opts.read_router_lookahead,
52	                                                                          segment_inf,
53	                                                                          is_flat,
54	                                                                          router_opts.route_verbosity,
55	                                                                          router_opts.device_model_warnings,
56	                                                                          router_opts.router_lookahead_interposer_base_cut_multiplier);
57	
58	    RouterDelayProfiler route_profiler(net_list, router_lookahead, is_flat);
59	
60	    int longest_length = get_longest_segment_length(segment_inf);
61	
62	    // now setup and compute the actual arrays
63	    std::unique_ptr<PlaceDelayModel> place_delay_model;
64	
65	    if (placer_opts.delay_model_type == PlaceDelayModelType::SIMPLE) {
66	        place_delay_model = std::make_unique<SimpleDelayModel>();
67	    } else if (placer_opts.delay_model_type == PlaceDelayModelType::DELTA) {
68	        place_delay_model = std::make_unique<DeltaDelayModel>(is_flat);
69	    } else if (placer_opts.delay_model_type == PlaceDelayModelType::DELTA_OVERRIDE) {
70	        place_delay_model = std::make_unique<OverrideDelayModel>(is_flat);
71	    } else {
72	        VTR_ASSERT_MSG(false, "Invalid placer delay model");
73	    }
74	
75	    if (placer_opts.read_placement_delay_lookup.empty()) {
76	        place_delay_model->compute(route_profiler, placer_opts, router_opts, longest_length);
77	    } else {
78	        place_delay_model->read(placer_opts.read_placement_delay_lookup);
79	    }
80	
81	    if (!placer_opts.write_placement_delay_lookup.empty()) {
82	        place_delay_model->write(placer_opts.write_placement_delay_lookup);
83	    }
84	
85	    // free all data structures that are no longer needed
86	    free_routing_structs();
87	
88	    return place_delay_model;
89	}
