32	void OverrideDelayModel::compute_override_delay_model_(RouterDelayProfiler& route_profiler,
33	                                                       const t_router_opts& router_opts) {
34	    const auto& device_ctx = g_vpr_ctx.device();
35	    t_router_opts router_opts2 = router_opts;
36	    router_opts2.astar_fac = 0.f;
37	    router_opts2.astar_offset = 0.f;
38	
39	    // Look at all the direct connections that exist, and add overrides to delay model
40	    for (int idirect = 0; idirect < (int)device_ctx.arch->directs.size(); ++idirect) {
41	        const t_direct_inf* direct = &device_ctx.arch->directs[idirect];
42	
43	        InstPort from_port = parse_inst_port(direct->from_pin);
44	        InstPort to_port = parse_inst_port(direct->to_pin);
45	
46	        t_physical_tile_type_ptr from_type = find_tile_type_by_name(from_port.instance_name(), device_ctx.physical_tile_types);
47	        t_physical_tile_type_ptr to_type = find_tile_type_by_name(to_port.instance_name(), device_ctx.physical_tile_types);
48	
49	        int num_conns = from_port.port_high_index() - from_port.port_low_index() + 1;
50	        VTR_ASSERT_MSG(num_conns == to_port.port_high_index() - to_port.port_low_index() + 1, "Directs must have the same size to/from");
51	
52	        //We now walk through all the connections associated with the current direct specification, measure
53	        //their delay and specify that value as an override in the delay model.
54	        //
55	        //Note that we need to check every connection in the direct to cover the case where the pins are not
56	        //equivalent.
57	        //
58	        //However, if the from/to ports are equivalent we could end up sampling the same RR SOURCE/SINK
59	        //paths multiple times (wasting CPU time) -- we avoid this by recording the sampled paths in
60	        //sampled_rr_pairs and skipping them if they occur multiple times.
61	        int missing_instances = 0;
62	        int missing_paths = 0;
63	        std::set<std::pair<RRNodeId, RRNodeId>> sampled_rr_pairs;
64	        for (int iconn = 0; iconn < num_conns; ++iconn) {
65	            //Find the associated pins
66	            int from_pin = from_type->find_pin(from_port.port_name(), from_port.port_low_index() + iconn);
67	            int to_pin = to_type->find_pin(to_port.port_name(), to_port.port_low_index() + iconn);
68	
69	            VTR_ASSERT(from_pin != UNDEFINED);
70	            VTR_ASSERT(to_pin != UNDEFINED);
71	
72	            int from_pin_class = from_type->find_pin_class(from_port.port_name(), from_port.port_low_index() + iconn, e_pin_type::DRIVER);
73	            VTR_ASSERT(from_pin_class != UNDEFINED);
74	
75	            int to_pin_class = to_type->find_pin_class(to_port.port_name(), to_port.port_low_index() + iconn, e_pin_type::RECEIVER);
76	            VTR_ASSERT(to_pin_class != UNDEFINED);
77	
78	            RRNodeId src_rr, sink_rr;
79	            bool found_sample_points = find_direct_connect_sample_locations(direct, from_type, from_pin, from_pin_class, to_type, to_pin, to_pin_class, src_rr, sink_rr);
80	
81	            if (!found_sample_points) {
82	                ++missing_instances;
83	                continue;
84	            }
85	
86	            //If some of the source/sink ports are logically equivalent we may have already
87	            //sampled the associated source/sink pair and don't need to do so again
88	            if (sampled_rr_pairs.contains({src_rr, sink_rr})) continue;
89	
90	            float direct_connect_delay = std::numeric_limits<float>::quiet_NaN();
91	            bool found_routing_path = route_profiler.calculate_delay(src_rr, sink_rr, router_opts2, &direct_connect_delay);
92	
93	            if (found_routing_path) {
94	                set_delay_override(from_type->index, from_pin_class, to_type->index, to_pin_class, direct->x_offset, direct->y_offset, direct_connect_delay);
95	            } else {
96	                ++missing_paths;
97	            }
98	
99	            //Record that we've sampled this pair of source and sink nodes
100	            sampled_rr_pairs.insert({src_rr, sink_rr});
101	        }
102	
103	        VTR_LOGV_WARN(missing_instances > 0, "Found no delta delay for %d bits of inter-block direct connect '%s' (no instances of this direct found)\n", missing_instances, direct->name.c_str());
104	        VTR_LOGV_WARN(missing_paths > 0, "Found no delta delay for %d bits of inter-block direct connect '%s' (no routing path found)\n", missing_paths, direct->name.c_str());
105	    }
106	}
