112	float OverrideDelayModel::delay(const t_physical_tile_loc& from_loc, int from_pin, const t_physical_tile_loc& to_loc, int to_pin) const {
113	    // First check to if there is an override delay value
114	    const auto& device_ctx = g_vpr_ctx.device();
115	    const auto& grid = device_ctx.grid;
116	
117	    t_physical_tile_type_ptr from_type_ptr = grid.get_physical_type(from_loc);
118	    t_physical_tile_type_ptr to_type_ptr = grid.get_physical_type(to_loc);
119	
120	    t_override override_key;
121	    override_key.from_type = from_type_ptr->index;
122	    override_key.from_class = from_type_ptr->pin_class[from_pin];
123	    override_key.to_type = to_type_ptr->index;
124	    override_key.to_class = to_type_ptr->pin_class[to_pin];
125	
126	    //Delay overrides may be different for +/- delta so do not use
127	    //an absolute delta for the look-up
128	    override_key.delta_x = to_loc.x - from_loc.x;
129	    override_key.delta_y = to_loc.y - from_loc.y;
130	
